import{_ as a,o as e,c as d,a2 as s}from"./chunks/framework.BFVZdVmd.js";const b=JSON.parse('{"title":"MySQL","description":"","frontmatter":{},"headers":[],"relativePath":"storage/mysql.md","filePath":"storage/mysql.md","lastUpdated":null}'),i={name:"storage/mysql.md"};function o(l,t,r,n,c,h){return e(),d("div",null,[...t[0]||(t[0]=[s(`<h1 id="mysql" tabindex="-1">MySQL <a class="header-anchor" href="#mysql" aria-label="Permalink to &quot;MySQL&quot;">​</a></h1><h2 id="是什么" tabindex="-1">是什么 <a class="header-anchor" href="#是什么" aria-label="Permalink to &quot;是什么&quot;">​</a></h2><p>MySQL 是最常见的关系型业务数据库，负责保存核心业务数据和事务数据。在企业 Java 项目中，它几乎是默认的存储选择。</p><h2 id="同类组件" tabindex="-1">同类组件 <a class="header-anchor" href="#同类组件" aria-label="Permalink to &quot;同类组件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>说明</th></tr></thead><tbody><tr><td><code>MySQL</code></td><td>最常见业务数据库</td></tr><tr><td><code>PostgreSQL</code></td><td>功能更强的关系型数据库</td></tr><tr><td><code>Oracle</code></td><td>金融、政企老系统常见</td></tr><tr><td><code>SQL Server</code></td><td>部分企业系统常见</td></tr></tbody></table><h2 id="连接池" tabindex="-1">连接池 <a class="header-anchor" href="#连接池" aria-label="Permalink to &quot;连接池&quot;">​</a></h2><p>数据库连接池负责管理和复用数据库连接，避免频繁创建销毁连接的开销。</p><table tabindex="0"><thead><tr><th>组件</th><th>说明</th></tr></thead><tbody><tr><td><code>HikariCP</code></td><td>Spring Boot 默认高性能数据库连接池</td></tr><tr><td><code>Druid</code></td><td>国内常用连接池，带监控能力</td></tr></tbody></table><h2 id="数据库版本管理" tabindex="-1">数据库版本管理 <a class="header-anchor" href="#数据库版本管理" aria-label="Permalink to &quot;数据库版本管理&quot;">​</a></h2><p>企业多人协作时，数据库表结构必须有版本管理，否则后期很容易混乱。</p><table tabindex="0"><thead><tr><th>组件</th><th>说明</th></tr></thead><tbody><tr><td><code>Flyway</code></td><td>数据库版本管理</td></tr><tr><td><code>Liquibase</code></td><td>数据库版本管理</td></tr></tbody></table><h2 id="常见组合" tabindex="-1">常见组合 <a class="header-anchor" href="#常见组合" aria-label="Permalink to &quot;常见组合&quot;">​</a></h2><p>国内企业项目常见组合：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MySQL + MyBatis-Plus + HikariCP / Druid</span></span></code></pre></div><p>建议补充版本管理：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Flyway / Liquibase</span></span></code></pre></div><h2 id="常见依赖" tabindex="-1">常见依赖 <a class="header-anchor" href="#常见依赖" aria-label="Permalink to &quot;常见依赖&quot;">​</a></h2><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mysql-connector-j</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flyway-core</span></span></code></pre></div><h2 id="选型建议" tabindex="-1">选型建议 <a class="header-anchor" href="#选型建议" aria-label="Permalink to &quot;选型建议&quot;">​</a></h2><ul><li>新项目默认 <code>MySQL</code>，连接池用默认的 <code>HikariCP</code> 即可，需要监控能力时再换 <code>Druid</code>。</li><li>多人协作项目从第一天就引入 <code>Flyway</code> 管理表结构变更。</li><li>需要更强功能（如复杂类型、向量检索）时考虑 <code>PostgreSQL</code>。</li></ul>`,20)])])}const u=a(i,[["render",o]]);export{b as __pageData,u as default};
